"use client";

import Link from "next/link";
import { Sparkles } from "lucide-react";
import { sanitizeNewsTitle } from "@/lib/sanitizeTitle";
import type { StockMention } from "@/types";

interface AiSummaryProps {
  title: string;
  aiSummary: string;
  relatedStocks?: StockMention[];
  onStockClick?: (code: string, name: string) => void;
}

/** AI 분석 텍스트를 섹션별로 파싱 */
function parseSections(text: string): { summary: string; sections: { title: string; content: string }[] } {
  if (!text?.trim()) return { summary: "", sections: [] };

  // 📌 한눈에 보는 핵심 팩트를 요약으로 추출
  const sectionEmojis = /^[📌🔍⚡💡]/m;
  const parts = text.split(/(?=^[📌🔍⚡💡])/m).filter(Boolean);

  let summary = "";
  const sections: { title: string; content: string }[] = [];

  for (const part of parts) {
    const firstLine = part.split("\n")[0]?.trim() ?? "";
    const content = part.split("\n").slice(1).join("\n").trim();

    if (firstLine.includes("핵심 팩트") || firstLine.startsWith("📌")) {
      summary = content;
    } else if (firstLine) {
      sections.push({ title: firstLine, content });
    }
  }

  // 섹션으로 파싱이 안 되면 전체를 요약으로
  if (!summary && sections.length === 0) {
    summary = text.trim();
  }

  return { summary, sections };
}

export default function AiSummary({ title, aiSummary, relatedStocks = [], onStockClick }: AiSummaryProps) {
  const { summary, sections } = parseSections(aiSummary);

  return (
    <>
      <h1 className="text-2xl font-bold">{sanitizeNewsTitle(title)}</h1>

      {/* 뉴스 요약 (핵심 팩트) */}
      {summary && (
        <div className="bg-skyblue/10 border border-skyblue/30 rounded-xl p-5">
          <div className="flex items-center gap-2 mb-3">
            <Sparkles className="w-5 h-5 text-skyblue" />
            <h2 className="font-bold text-skyblue">📌 한눈에 보는 핵심 팩트</h2>
          </div>
          <div className="text-gray-200 leading-relaxed whitespace-pre-wrap">{summary}</div>
        </div>
      )}

      {/* 항목별 분석 카드 */}
      {sections.length > 0 && (
        <div className="space-y-3">
          {sections.map((sec, i) => (
            <div
              key={i}
              className="bg-white/5 border border-white/10 rounded-xl p-4"
            >
              <h3 className="font-bold text-skyblue mb-2 text-sm">{sec.title}</h3>
              <div className="text-gray-200 text-sm leading-relaxed whitespace-pre-wrap">
                {sec.content}
              </div>
            </div>
          ))}
        </div>
      )}

      {relatedStocks.length > 0 && (
        <div>
          <h2 className="text-lg font-bold mb-3">💡 그래서 어떤 종목?</h2>
          <div className="space-y-2">
            {relatedStocks.map((s, i) =>
              onStockClick ? (
                <button
                  key={i}
                  type="button"
                  onClick={() => onStockClick(s.stock_code, s.stock_name)}
                  className="w-full text-left block bg-white/5 border border-white/10 rounded-xl p-4 hover:bg-white/10 transition-colors"
                >
                  <div className="flex justify-between items-center gap-3">
                    <div>
                      <div className="flex items-center gap-2">
                        <p className="font-medium">{s.stock_name}</p>
                        {s.type && (
                          <span className={`text-[10px] px-1.5 py-0.5 rounded ${
                            s.type === "direct" ? "bg-amber-500/20 text-amber-400" : "bg-skyblue/20 text-skyblue"
                          }`}>
                            {s.type === "direct" ? "직접 수혜" : "낙수 효과"}
                          </span>
                        )}
                      </div>
                      <p className="text-xs text-gray-400">{s.stock_code}</p>
                    </div>
                    <div className="text-right flex-shrink-0 max-w-[50%]">
                      <p className="text-sm text-gray-300">{s.reason}</p>
                      <p className="text-xs text-skyblue mt-1">AI 분석 보기 →</p>
                    </div>
                  </div>
                </button>
              ) : (
                <Link
                  key={i}
                  href={`/stock/${s.stock_code}`}
                  className="block bg-white/5 border border-white/10 rounded-xl p-4 hover:bg-white/10 transition-colors"
                >
                  <div className="flex justify-between items-center gap-3">
                    <div>
                      <div className="flex items-center gap-2">
                        <p className="font-medium">{s.stock_name}</p>
                        {s.type && (
                          <span className={`text-[10px] px-1.5 py-0.5 rounded ${
                            s.type === "direct" ? "bg-amber-500/20 text-amber-400" : "bg-skyblue/20 text-skyblue"
                          }`}>
                            {s.type === "direct" ? "직접 수혜" : "낙수 효과"}
                          </span>
                        )}
                      </div>
                      <p className="text-xs text-gray-400">{s.stock_code}</p>
                    </div>
                    <p className="text-sm text-gray-300 flex-shrink-0 max-w-[50%]">{s.reason}</p>
                  </div>
                </Link>
              )
            )}
          </div>
        </div>
      )}
    </>
  );
}
