"use client";

import { useState, useEffect } from "react";
import { useParams } from "next/navigation";
import { fetchNewsSummary, fetchStockAnalysis } from "@/lib/api";
import type { StockMention, StockAnalysis } from "@/types";
import LoadingSpinner from "@/components/ui/LoadingSpinner";
import ErrorMessage from "@/components/ui/ErrorMessage";
import AiSummary from "@/components/news/AiSummary";
import Link from "next/link";
import { ArrowLeft, Sparkles, Star, TrendingUp, TrendingDown, Minus } from "lucide-react";

// ── 인라인 종목 분석 패널 ──────────────────────────────────────────
function StockAnalysisPanel({ code, name }: { code: string; name: string }) {
  const [analysis, setAnalysis] = useState<StockAnalysis | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");

  useEffect(() => {
    setLoading(true);
    setError("");
    fetchStockAnalysis(code)
      .then(setAnalysis)
      .catch((e) => setError(e?.message || "분석 중 오류"))
      .finally(() => setLoading(false));
  }, [code]);

  const sentimentColor: Record<string, string> = {
    bullish: "bg-green-500/20 text-green-300 border-green-500/30",
    bearish: "bg-red-500/20 text-red-300 border-red-500/30",
    neutral: "bg-gray-500/20 text-gray-300 border-gray-500/30",
  };

  if (loading) return <LoadingSpinner text={`${name} 분석 중... (최대 1분)`} />;
  if (error) return (
    <div className="bg-red-500/10 border border-red-500/30 rounded-xl p-4 text-sm text-red-300">{error}</div>
  );
  if (!analysis) return null;

  return (
    <div className="space-y-3">
      <div className="flex items-center gap-3">
        <Sparkles className="w-5 h-5 text-skyblue" />
        <div className="flex-1">
          <p className="font-bold">{analysis.stock_name} AI 분석</p>
          <p className="text-xs text-gray-400">{new Date(analysis.analyzed_at).toLocaleString("ko-KR")} 기준</p>
        </div>
        <span className={`text-xs font-bold px-2 py-1 rounded-full border ${sentimentColor[analysis.sentiment] ?? sentimentColor.neutral}`}>
          {analysis.sentiment === "bullish" ? "긍정" : analysis.sentiment === "bearish" ? "부정" : "중립"}
        </span>
      </div>

      {analysis.items.map((item, i) => (
        <div key={i} className="bg-white/5 border border-white/10 rounded-xl p-3 space-y-1">
          <div className="flex justify-between gap-2">
            <span className="text-xs text-gray-400">{item.label}</span>
            <span className="text-sm font-bold text-right">{item.result}</span>
          </div>
          <p className="text-sm text-gray-200">{item.reason}</p>
          <p className="text-xs text-gray-500">{item.description}</p>
        </div>
      ))}

      <div className="bg-skyblue/10 border border-skyblue/30 rounded-xl p-4 text-center space-y-2">
        <div className="flex justify-center gap-1">
          {[1, 2, 3, 4, 5].map((n) => (
            <Star key={n} className={`w-6 h-6 ${n <= analysis.overall_score ? "text-amber-400 fill-amber-400" : "text-gray-600"}`} />
          ))}
        </div>
        <p className="text-sm text-gray-200">{analysis.overall_comment}</p>
      </div>

      <Link
        href={`/stock/${code}`}
        className="block text-center text-sm text-skyblue hover:underline"
      >
        {name} 상세 페이지로 →
      </Link>
    </div>
  );
}

// ── 관련 종목 선택 목록 ───────────────────────────────────────────
function RelatedStockList({
  stocks,
  selectedCode,
  onSelect,
}: {
  stocks: StockMention[];
  selectedCode: string | null;
  onSelect: (code: string, name: string) => void;
}) {
  return (
    <div className="space-y-2">
      {stocks.map((s, i) => {
        const isSelected = selectedCode === s.stock_code;
        return (
          <button
            key={i}
            type="button"
            onClick={() => onSelect(s.stock_code, s.stock_name)}
            className={`w-full text-left rounded-xl p-4 border transition-colors ${
              isSelected
                ? "bg-skyblue/10 border-skyblue/40"
                : "bg-white/5 border-white/10 hover:bg-white/10"
            }`}
          >
            <div className="flex justify-between items-center gap-3">
              <div>
                <div className="flex items-center gap-2">
                  <p className="font-medium">{s.stock_name}</p>
                  {s.type && (
                    <span className={`text-[10px] px-1.5 py-0.5 rounded ${
                      s.type === "direct" ? "bg-amber-500/20 text-amber-400" : "bg-skyblue/20 text-skyblue"
                    }`}>
                      {s.type === "direct" ? "직접 수혜" : "낙수 효과"}
                    </span>
                  )}
                </div>
                <p className="text-xs text-gray-400">{s.stock_code}</p>
              </div>
              <p className="text-sm text-gray-300 text-right max-w-[50%]">{s.reason}</p>
            </div>
            {isSelected && (
              <p className="text-xs text-skyblue mt-2">▼ AI 분석 보는 중...</p>
            )}
          </button>
        );
      })}
    </div>
  );
}

// ── 메인 페이지 ───────────────────────────────────────────────────
type Tab = "news" | "stocks";

export default function NewsDetailPage() {
  const { id: rawId } = useParams<{ id: string }>();
  const id = decodeURIComponent(rawId);
  const [data, setData] = useState<any>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");
  const [tab, setTab] = useState<Tab>("news");
  const [selectedStock, setSelectedStock] = useState<{ code: string; name: string } | null>(null);

  const load = () => {
    setLoading(true);
    setError("");
    fetchNewsSummary(id)
      .then(setData)
      .catch((e) => setError(e.message))
      .finally(() => setLoading(false));
  };

  useEffect(() => { load(); }, [id]);

  const relatedStocks: StockMention[] = data?.related_stocks ?? [];
  const hasStocks = relatedStocks.length > 0;

  const handleSelectStock = (code: string, name: string) => {
    setSelectedStock({ code, name });
  };

  return (
    <div className="space-y-4 max-w-2xl mx-auto">
      <Link href="/issues" className="inline-flex items-center text-gray-400 hover:text-white text-sm transition-colors">
        <ArrowLeft className="w-4 h-4 mr-1" /> 목록으로
      </Link>

      {loading && <LoadingSpinner text="쉬운 말로 정리하고 있어요..." />}
      {error && <ErrorMessage message={error} onRetry={load} />}

      {data && (
        <>
          {/* 탭 헤더 */}
          {hasStocks && (
            <div className="flex gap-1 bg-white/5 p-1 rounded-xl">
              <button
                type="button"
                onClick={() => setTab("news")}
                className={`flex-1 py-2 rounded-lg text-sm font-medium transition-colors ${
                  tab === "news" ? "bg-skyblue/20 text-skyblue" : "text-gray-400 hover:text-white"
                }`}
              >
                AI 분석
              </button>
              <button
                type="button"
                onClick={() => setTab("stocks")}
                className={`flex-1 py-2 rounded-lg text-sm font-medium transition-colors ${
                  tab === "stocks" ? "bg-skyblue/20 text-skyblue" : "text-gray-400 hover:text-white"
                }`}
              >
                관련 종목 보기 ({relatedStocks.length})
              </button>
            </div>
          )}

          {/* 탭: AI 분석 */}
          {tab === "news" && (
            <AiSummary
              title={data.title}
              aiSummary={data.ai_summary}
              relatedStocks={relatedStocks}
              onStockClick={(code, name) => {
                setSelectedStock({ code, name });
                setTab("stocks");
              }}
            />
          )}

          {/* 탭: 관련 종목 보기 */}
          {tab === "stocks" && (
            <div className="space-y-4">
              <h2 className="text-lg font-bold">💡 그래서 어떤 종목?</h2>
              <RelatedStockList
                stocks={relatedStocks}
                selectedCode={selectedStock?.code ?? null}
                onSelect={handleSelectStock}
              />
              {selectedStock && (
                <div className="mt-2">
                  <StockAnalysisPanel code={selectedStock.code} name={selectedStock.name} />
                </div>
              )}
            </div>
          )}
        </>
      )}
    </div>
  );
}
